#include <vector>
#include <iostream>

#define likely(x) __builtin_expect(!!(x), 1)
#define unlikely(x) __builtin_expect(!!(x), 0)

void process(const std::vector<int>& v) {
  if (likely(!v.empty())) { // Noncompliant
    std::cout << v[0] << '\n';
  }
  if (unlikely(v.size() > 1000)) { // Noncompliant
    std::cout << "Large vector\n";
  }
}

void checkPointer(int* ptr) {
  if (__builtin_expect(ptr != nullptr, 1)) { // Noncompliant
    *ptr = 42;
  }
}

compliant:
#include <vector>
#include <iostream>

void process(const std::vector<int>& v) {
  if (!v.empty()) [[likely]] { // Compliant - C++20 attribute
    std::cout << v[0] << '\n';
  }
  if (v.size() > 1000) [[unlikely]] { // Compliant
    std::cout << "Large vector\n";
  }
}

void checkPointer(int* ptr) {
  if (ptr != nullptr) [[likely]] { // Compliant
    *ptr = 42;
  }
}
